seed_files.core/handlers.py:
"""Event handlers — one handler class per event type.

Handlers are registered via the @register_handler decorator.
Each handler must implement process(event) and return a result dict.
"""
from core.events import EventType


# --- Handler registry (populated by @register_handler) ---
_HANDLER_REGISTRY = {}


def register_handler(event_type):
    """Decorator that registers a handler class for an event type."""
    def decorator(cls):
        _HANDLER_REGISTRY[event_type] = cls
        cls.event_type = event_type
        return cls
    return decorator


def get_handler(event_type):
    """Look up the handler class for an event type."""
    if event_type not in _HANDLER_REGISTRY:
        raise KeyError(f"No handler registered for {event_type}")
    return _HANDLER_REGISTRY[event_type]


def list_handlers():
    """Return dict of all registered handlers."""
    return dict(_HANDLER_REGISTRY)


class BaseHandler:
    """Base class for all event handlers."""

    event_type = None

    def process(self, event: dict) -> dict:
        raise NotImplementedError

    def validate(self, event: dict) -> bool:
        """Basic validation — override for type-specific checks."""
        return "type" in event and "timestamp" in event


@register_handler(EventType.CLICK)
class ClickHandler(BaseHandler):
    """Handles click events."""

    def process(self, event: dict) -> dict:
        return {
            "handled": True,
            "handler": "click",
            "element": event.get("element", "unknown"),
            "coordinates": event.get("coordinates", [0, 0]),
        }


@register_handler(EventType.SUBMIT)
class SubmitHandler(BaseHandler):
    """Handles form submission events."""

    def process(self, event: dict) -> dict:
        return {
            "handled": True,
            "handler": "submit",
            "form_id": event.get("form_id", ""),
            "field_count": len(event.get("fields", {})),
        }


@register_handler(EventType.LOAD)
class LoadHandler(BaseHandler):
    """Handles page load events."""

    def process(self, event: dict) -> dict:
        return {
            "handled": True,
            "handler": "load",
            "url": event.get("url", ""),
            "load_time_ms": event.get("load_time_ms", 0),
        }


@register_handler(EventType.ERROR)
class ErrorHandler(BaseHandler):
    """Handles error events."""

    def process(self, event: dict) -> dict:
        return {
            "handled": True,
            "handler": "error",
            "error_code": event.get("error_code", "UNKNOWN"),
            "message": event.get("message", ""),
            "severity": event.get("severity", "warning"),
        }


@register_handler(EventType.CUSTOM)
class CustomHandler(BaseHandler):
    """Handles custom/generic events."""

    def process(self, event: dict) -> dict:
        return {
            "handled": True,
            "handler": "custom",
            "custom_type": event.get("custom_type", "generic"),
            "payload": event.get("payload", {}),
        }

seed_files.core/pipeline.py:
"""Event processing pipeline.

Routes incoming events to the correct handler and runs them through
the configured plugin chain (filter -> transform -> handle -> analytics).
"""
from core.events import EventType
from core.handlers import (
    ClickHandler, SubmitHandler, LoadHandler,
    ErrorHandler, CustomHandler,
)


# Explicit mapping from EventType to handler CLASS.
# This is intentionally NOT using the handler registry — the pipeline
# maintains its own routing table for initialization-order control.
PIPELINE_ROUTES = {
    EventType.CLICK: ClickHandler,
    EventType.SUBMIT: SubmitHandler,
    EventType.LOAD: LoadHandler,
    EventType.ERROR: ErrorHandler,
    EventType.CUSTOM: CustomHandler,
}


class EventPipeline:
    """Processes events through the full plugin chain."""

    def __init__(self, plugins=None):
        self._plugins = plugins or []
        self._handlers = {}
        self._processed_count = 0
        self._init_handlers()

    def _init_handlers(self):
        """Instantiate one handler per route."""
        for etype, handler_cls in PIPELINE_ROUTES.items():
            self._handlers[etype] = handler_cls()

    def route(self, event: dict) -> dict:
        """Route an event to its handler and return the result."""
        raw_type = event.get("type")
        if isinstance(raw_type, str):
            try:
                etype = EventType[raw_type.upper()]
            except KeyError:
                raise ValueError(f"Unknown event type: {raw_type}")
        elif isinstance(raw_type, EventType):
            etype = raw_type
        else:
            raise ValueError(f"Invalid event type: {raw_type}")

        handler = self._handlers.get(etype)
        if handler is None:
            raise ValueError(f"No pipeline route for {etype}")

        self._processed_count += 1
        return handler.process(event)

    def process(self, event: dict) -> dict:
        """Full pipeline: filter -> transform -> route -> analytics."""
        # Run through plugins that implement pre_process
        for plugin in self._plugins:
            if hasattr(plugin, "pre_process"):
                event = plugin.pre_process(event)
                if event is None:
                    return {"filtered": True}

        result = self.route(event)

        # Run through plugins that implement post_process
        for plugin in self._plugins:
            if hasattr(plugin, "post_process"):
                plugin.post_process(event, result)

        return result

    @property
    def processed_count(self):
        return self._processed_count

    def get_routes(self):
        """Return the current routing table."""
        return dict(PIPELINE_ROUTES)

seed_files.core/serializer.py:
"""Event serializer — converts events to/from wire format.

Each event type has a specific serialization format. The serializer
uses type-specific format strings and field extraction logic.
"""
import json
from core.events import EventType


# Format templates per event type (used for human-readable logging)
FORMAT_TEMPLATES = {
    EventType.CLICK: "[CLICK] element={element} coords=({x},{y}) at {timestamp}",
    EventType.SUBMIT: "[SUBMIT] form={form_id} fields={field_count} at {timestamp}",
    EventType.LOAD: "[LOAD] url={url} time={load_time_ms}ms at {timestamp}",
    EventType.ERROR: "[ERROR] code={error_code} severity={severity} msg={message} at {timestamp}",
    EventType.CUSTOM: "[CUSTOM] subtype={custom_type} at {timestamp}",
}


def serialize_event(event: dict) -> str:
    """Serialize an event dict to JSON string."""
    return json.dumps(event, default=str)


def deserialize_event(data: str) -> dict:
    """Deserialize a JSON string to event dict."""
    return json.loads(data)


def format_event(event: dict) -> str:
    """Format an event as a human-readable log line.

    Uses type-specific format templates. Falls back to JSON for
    unknown types.
    """
    raw_type = event.get("type", "")
    if isinstance(raw_type, str):
        try:
            etype = EventType[raw_type.upper()]
        except KeyError:
            return json.dumps(event)
    elif isinstance(raw_type, EventType):
        etype = raw_type
    else:
        return json.dumps(event)

    template = FORMAT_TEMPLATES.get(etype)
    if template is None:
        return json.dumps(event)

    # Build format kwargs from event, providing defaults
    kwargs = dict(event)
    kwargs.setdefault("element", "?")
    kwargs.setdefault("x", 0)
    kwargs.setdefault("y", 0)
    kwargs.setdefault("form_id", "?")
    kwargs.setdefault("field_count", 0)
    kwargs.setdefault("url", "?")
    kwargs.setdefault("load_time_ms", 0)
    kwargs.setdefault("error_code", "?")
    kwargs.setdefault("severity", "?")
    kwargs.setdefault("message", "?")
    kwargs.setdefault("custom_type", "?")
    kwargs.setdefault("timestamp", "?")

    return template.format(**kwargs)


def get_supported_formats() -> list:
    """Return list of event types that have format templates."""
    return list(FORMAT_TEMPLATES.keys())

seed_files.plugins/filter.py:
"""Filter plugin — applies type-specific filtering rules.

Each event type has its own filter predicate. Events that fail
the filter are dropped from the pipeline (pre_process returns None).
"""
from core.events import EventType


# Type-specific filter rules.
# Each rule is a callable(event) -> bool.  Return True to KEEP the event.
FILTER_RULES = {
    "CLICK": lambda e: e.get("element") is not None,
    "SUBMIT": lambda e: bool(e.get("form_id")),
    "LOAD": lambda e: bool(e.get("url")),
    "ERROR": lambda e: e.get("severity", "info") in ("warning", "error", "critical"),
    "CUSTOM": lambda e: True,  # custom events always pass
}


class FilterPlugin:
    """Pre-process plugin that filters events by type-specific rules."""

    def __init__(self, enabled=True):
        self.enabled = enabled
        self.filtered_count = 0
        self.passed_count = 0

    def pre_process(self, event: dict) -> dict | None:
        """Filter the event. Returns None to drop it."""
        if not self.enabled:
            self.passed_count += 1
            return event

        raw_type = event.get("type", "")
        if isinstance(raw_type, EventType):
            type_str = raw_type.name
        else:
            type_str = str(raw_type).upper()

        rule = FILTER_RULES.get(type_str)
        if rule is None:
            # Unknown type — drop it
            self.filtered_count += 1
            return None

        if rule(event):
            self.passed_count += 1
            return event
        else:
            self.filtered_count += 1
            return None

    def get_stats(self) -> dict:
        return {
            "filtered": self.filtered_count,
            "passed": self.passed_count,
        }

seed_files.plugins/transformer.py:
"""Transformer plugin — normalizes events before processing.

Each event type has specific normalization logic implemented as
a method named _transform_{type}. The pre_process hook dispatches
to the appropriate method.
"""
from core.events import EventType


class TransformerPlugin:
    """Pre-process plugin that normalizes event data."""

    def __init__(self):
        self.transformed_count = 0

    def pre_process(self, event: dict) -> dict:
        """Normalize the event based on its type."""
        raw_type = event.get("type", "")
        if isinstance(raw_type, EventType):
            type_str = raw_type.name.lower()
        else:
            type_str = str(raw_type).lower()

        method = getattr(self, f"_transform_{type_str}", None)
        if method:
            event = method(event)
            self.transformed_count += 1
        return event

    def _transform_click(self, event: dict) -> dict:
        """Normalize click coordinates to integers."""
        if "coordinates" in event:
            coords = event["coordinates"]
            event["coordinates"] = [int(c) for c in coords]
            event["x"] = event["coordinates"][0]
            event["y"] = event["coordinates"][1]
        return event

    def _transform_submit(self, event: dict) -> dict:
        """Normalize form_id to lowercase."""
        if "form_id" in event:
            event["form_id"] = event["form_id"].strip().lower()
        return event

    def _transform_load(self, event: dict) -> dict:
        """Normalize URL to lowercase and strip trailing slash."""
        if "url" in event:
            event["url"] = event["url"].strip().lower().rstrip("/")
        return event

    def _transform_error(self, event: dict) -> dict:
        """Normalize severity to lowercase."""
        if "severity" in event:
            event["severity"] = event["severity"].strip().lower()
        return event

    def _transform_custom(self, event: dict) -> dict:
        """Normalize custom_type to lowercase."""
        if "custom_type" in event:
            event["custom_type"] = event["custom_type"].strip().lower()
        return event

seed_files.api/endpoints.py:
"""API endpoint definitions for the event processing system.

Each event type has a dedicated endpoint with type-specific
request/response handling. Endpoints are defined as route dicts
in the ROUTES list.
"""
from core.events import EventType
from api.validators import validate_event


# Route definitions — each is a dict with path, method, event_type, and handler.
ROUTES = [
    {
        "path": "/events/click",
        "method": "POST",
        "event_type": EventType.CLICK,
        "description": "Submit a click event",
        "required_fields": ["element", "timestamp"],
    },
    {
        "path": "/events/submit",
        "method": "POST",
        "event_type": EventType.SUBMIT,
        "description": "Submit a form submission event",
        "required_fields": ["form_id", "timestamp"],
    },
    {
        "path": "/events/load",
        "method": "POST",
        "event_type": EventType.LOAD,
        "description": "Submit a page load event",
        "required_fields": ["url", "timestamp"],
    },
    {
        "path": "/events/error",
        "method": "POST",
        "event_type": EventType.ERROR,
        "description": "Submit an error event",
        "required_fields": ["error_code", "message", "timestamp"],
    },
    {
        "path": "/events/custom",
        "method": "POST",
        "event_type": EventType.CUSTOM,
        "description": "Submit a custom event",
        "required_fields": ["timestamp"],
    },
]


def get_route(event_type: EventType) -> dict | None:
    """Look up the route dict for a given event type."""
    for route in ROUTES:
        if route["event_type"] == event_type:
            return route
    return None


def handle_request(path: str, body: dict) -> dict:
    """Simulate handling an API request."""
    route = None
    for r in ROUTES:
        if r["path"] == path:
            route = r
            break

    if route is None:
        return {"status": 404, "error": f"No route for {path}"}

    # Validate
    body["type"] = route["event_type"].name
    errors = validate_event(body, route["event_type"])
    if errors:
        return {"status": 400, "errors": errors}

    return {"status": 200, "accepted": True, "event_type": route["event_type"].name}


def list_routes() -> list:
    """Return all route paths."""
    return [r["path"] for r in ROUTES]

seed_files.api/validators.py:
"""Request validators for each event type.

Each event type has a validator class with a validate(data) method
that returns a list of error strings (empty = valid).
"""
from core.events import EventType


class BaseValidator:
    """Base validator with common checks."""

    required_fields = ["type", "timestamp"]

    def validate(self, data: dict) -> list:
        errors = []
        for field in self.required_fields:
            if field not in data or data[field] is None:
                errors.append(f"Missing required field: {field}")
        return errors


class ClickValidator(BaseValidator):
    required_fields = ["type", "timestamp", "element"]

    def validate(self, data: dict) -> list:
        errors = super().validate(data)
        if "coordinates" in data:
            coords = data["coordinates"]
            if not isinstance(coords, (list, tuple)) or len(coords) != 2:
                errors.append("coordinates must be a list of [x, y]")
        return errors


class SubmitValidator(BaseValidator):
    required_fields = ["type", "timestamp", "form_id"]

    def validate(self, data: dict) -> list:
        errors = super().validate(data)
        if "form_id" in data and not isinstance(data["form_id"], str):
            errors.append("form_id must be a string")
        return errors


class LoadValidator(BaseValidator):
    required_fields = ["type", "timestamp", "url"]

    def validate(self, data: dict) -> list:
        errors = super().validate(data)
        if "load_time_ms" in data:
            if not isinstance(data["load_time_ms"], (int, float)):
                errors.append("load_time_ms must be a number")
            elif data["load_time_ms"] < 0:
                errors.append("load_time_ms must be non-negative")
        return errors


class ErrorValidator(BaseValidator):
    required_fields = ["type", "timestamp", "error_code", "message"]

    def validate(self, data: dict) -> list:
        errors = super().validate(data)
        valid_severities = ("info", "warning", "error", "critical")
        sev = data.get("severity", "warning")
        if sev not in valid_severities:
            errors.append(f"severity must be one of {valid_severities}")
        return errors


class CustomValidator(BaseValidator):
    required_fields = ["type", "timestamp"]

    def validate(self, data: dict) -> list:
        return super().validate(data)


# Validator registry — maps EventType to validator INSTANCE
VALIDATORS = {
    EventType.CLICK: ClickValidator(),
    EventType.SUBMIT: SubmitValidator(),
    EventType.LOAD: LoadValidator(),
    EventType.ERROR: ErrorValidator(),
    EventType.CUSTOM: CustomValidator(),
}


def validate_event(data: dict, event_type: EventType) -> list:
    """Validate an event dict against its type-specific rules."""
    validator = VALIDATORS.get(event_type)
    if validator is None:
        return [f"No validator for event type: {event_type}"]
    return validator.validate(data)

